```ts
/**
 * Get all nodes in a workflow where the node credential is not accessible to the user.
 */
function getNodesWithInaccessibleCreds(workflow: WorkflowEntity, userCredIds: string[]) {
	return workflow.nodes.filter((node) => {
		if (!node.credentials) return false;

		return Object.values(node.credentials)
			.map((nodeCred) => nodeCred.id)
			.some((nodeCredId) => nodeCredId !== null && !userCredIds.includes(nodeCredId));
	});
}

/**
 * Validate whether a new version of a workflow has been tampered with.
 */
export function validateNodeCredAccess(
	newWorkflow: WorkflowEntity,
	prevWorkflow: WorkflowEntity,
	userCreds: string[],
) {
	const nodesWithInaccesibleCreds = getNodesWithInaccessibleCreds(newWorkflow, userCreds);

	if (!nodesWithInaccesibleCreds.length) return newWorkflow;

	const prevWorkflowNodeIds = prevWorkflow.nodes.map((node) => node.id);

	const isTamperingAttempt = (prevWorkflowNodeIds: string[], inaccessibleCredNodeId: string) =>
	!prevWorkflowNodeIds.includes(inaccessibleCredNodeId);

	nodesWithInaccesibleCreds.forEach((node, index) => {
		if (isTamperingAttempt(prevWorkflowNodeIds, node.id)) {
			throw new Error('Workflow contains new nodes with credentials inaccessible to user');
		}

		// as a precaution, replace node in new worfklow with node in existing workflow
		newWorkflow.nodes[index] = prevWorkflow.nodes.find((prevNode) => prevNode.id === node.id)!;
	});

	return newWorkflow;
}
